1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const RUNE_BLOCK_OF_3_PRICE = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	type Item = { type: string };
14	type QuoteStep = { type: "quote"; items: Item[] };
15	type Scenario = { steps: QuoteStep[] };
16	
17	function sumPerItemBasePremiums(items: Item[]): number {
18	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
19	}
20	
21	function isRuneBlockOfThree(items: Item[]): boolean {
22	  return items.length === 3 && items.every((item) => item.type === "rune");
23	}
24	
25	function calculateBasePremium(items: Item[]): number {
26	  if (isRuneBlockOfThree(items)) {
27	    return RUNE_BLOCK_OF_3_PRICE;
28	  }
29	  return sumPerItemBasePremiums(items);
30	}
31	
32	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
33	  const { steps } = scenario as Scenario;
34	  const items = steps[0].items;
35	  const basePremium = calculateBasePremium(items);
36	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
37	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
38	  return { results: [{ premium }] };
39	}
